'use client';

import * as THREE from 'three';
import { useMemo } from 'react';
import { PortalSurface } from './PortalSurface';
import { makeArchRing } from './archShape';

interface PortalProps {
  /** App accent colour, e.g. '#38C5A2'. */
  color: string;
  /** Randomises the vortex swirl per bay. */
  seed?: number;
}

export function Portal({ color, seed = 0 }: PortalProps) {
  const ringGeometry = useMemo(() => new THREE.ShapeGeometry(makeArchRing()), []);

  return (
    <group position={[0, 0, 0.42]}>
      {/* Dark backing so nothing leaks behind the swirl */}
      <mesh position={[0, 0, -0.02]} receiveShadow>
        <boxGeometry args={[1.7, 6.2, 0.12]} />
        <meshStandardMaterial color="#050608" roughness={1} metalness={0} />
      </mesh>

      {/* The animated vortex */}
      <PortalSurface color={color} seed={seed} />

      {/* Glowing lip hugging the stone opening (additive → bloom halo) */}
      <mesh geometry={ringGeometry} position={[0, 0, 0.05]}>
        <meshBasicMaterial
          color={color}
          transparent
          opacity={0.9}
          blending={THREE.AdditiveBlending}
          toneMapped={false}
          side={THREE.DoubleSide}
          depthWrite={false}
        />
      </mesh>

      {/* Reveals — thin returns framing the opening */}
      <mesh position={[-0.95, 0, 0.08]} receiveShadow>
        <boxGeometry args={[0.18, 6.2, 0.18]} />
        <meshStandardMaterial color="#2a2d31" roughness={1} />
      </mesh>
      <mesh position={[0.95, 0, 0.08]} receiveShadow>
        <boxGeometry args={[0.18, 6.2, 0.18]} />
        <meshStandardMaterial color="#2a2d31" roughness={1} />
      </mesh>
      <mesh position={[0, 3.1, 0.08]} receiveShadow>
        <boxGeometry args={[2.08, 0.22, 0.18]} />
        <meshStandardMaterial color="#2a2d31" roughness={1} />
      </mesh>

      {/* Coloured light spilling from the portal onto the surrounding stone */}
      <pointLight
        position={[0, 0.4, 1.4]}
        color={color}
        intensity={6}
        distance={9}
        decay={2}
      />
    </group>
  );
}
