interface PillarProps {
  side: 'left' | 'right';
}

export function Pillar({ side }: PillarProps) {
  const x = side === 'left' ? -1.22 : 1.22;

  return (
    <mesh position={[x, 0, 0.08]} receiveShadow castShadow>
      <boxGeometry args={[0.7, 6.2, 0.55]} />
      <meshStandardMaterial
        color="#3b3d43"
        roughness={0.95}
        metalness={0.02}
      />
    </mesh>
  );
}
