'use client';

import * as THREE from 'three';
import { useMemo } from 'react';

/** Radii for the concentric inlaid circles etched into the floor. */
const RING_RADII = [3.2, 6.4, 9.6, 12.8, 16, 19.2, 22.4];

export function Floor() {
  const rings = useMemo(
    () =>
      RING_RADII.map((r) => ({
        radius: r,
        geometry: new THREE.RingGeometry(r - 0.035, r + 0.035, 160),
      })),
    []
  );

  return (
    <group rotation={[-Math.PI / 2, 0, 0]}>
      {/* Polished dark stone floor */}
      <mesh receiveShadow>
        <circleGeometry args={[26, 160]} />
        <meshStandardMaterial
          color="#0e1016"
          roughness={0.35}
          metalness={0.55}
          side={THREE.DoubleSide}
        />
      </mesh>

      {/* Faint inlaid concentric circles (kept below the bloom threshold) */}
      {rings.map(({ radius, geometry }) => (
        <mesh key={radius} geometry={geometry} position={[0, 0, 0.01]}>
          <meshBasicMaterial
            color="#4a5b7a"
            transparent
            opacity={0.35}
            side={THREE.DoubleSide}
            toneMapped={false}
            depthWrite={false}
          />
        </mesh>
      ))}

      {/* Soft central pool of light in the middle of the room */}
      <mesh position={[0, 0, 0.005]}>
        <circleGeometry args={[3.6, 96]} />
        <meshBasicMaterial
          color="#1a2438"
          transparent
          opacity={0.5}
          side={THREE.DoubleSide}
          toneMapped={false}
          depthWrite={false}
        />
      </mesh>
    </group>
  );
}
